import { Component, computed, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute, Router } from '@angular/router';
import { toSignal } from '@angular/core/rxjs-interop';
import { map } from 'rxjs/operators';
import { Category } from '../../core/models';
import { CategoryChipComponent } from '../../shared/category-chip/category-chip.component';
import { EmptyStateComponent } from '../../shared/empty-state/empty-state.component';

@Component({
  selector: 'app-admin-categories',
  standalone: true,
  imports: [CommonModule, FormsModule, CategoryChipComponent, EmptyStateComponent],
  templateUrl: './admin-categories.component.html',
  styleUrl: './admin-categories.component.css',
})
export class AdminCategoriesComponent {
  private route = inject(ActivatedRoute);
  private router = inject(Router);

  // --- Backend-provided data (data-contract signals) ------------------------------------
  categories = signal<Category[]>([
    { id: 'c1', name: 'Tech', sourceCount: 2, articleCount: 202 },
    { id: 'c2', name: 'Sports', sourceCount: 1, articleCount: 96 },
    { id: 'c3', name: 'World News', sourceCount: 1, articleCount: 210 },
    { id: 'c4', name: 'Business', sourceCount: 1, articleCount: 0 },
    { id: 'c5', name: 'Science', sourceCount: 0, articleCount: 0 },
  ]);

  readonly modalOpen = toSignal(
    this.route.queryParamMap.pipe(map((p) => p.get('modal') === 'add-category')),
    { initialValue: false },
  );

  newName = '';
  submitError = '';
  submitting = false;
  rowError = signal<{ id: string; message: string } | null>(null);
  toast = signal('');

  readonly hasCategories = computed(() => this.categories().length > 0);

  openAddModal(): void {
    this.router.navigate([], {
      relativeTo: this.route,
      queryParams: { modal: 'add-category' },
      queryParamsHandling: 'merge',
    });
  }

  closeModal(): void {
    this.submitError = '';
    this.router.navigate([], {
      relativeTo: this.route,
      queryParams: { modal: null },
      queryParamsHandling: 'merge',
    });
  }

  addCategory(): void {
    this.submitError = '';
    const name = this.newName.trim();
    if (!name) {
      this.submitError = 'Enter a category name.';
      return;
    }
    // The real API returns 409 when the name already exists.
    const exists = this.categories().some((c) => c.name.toLowerCase() === name.toLowerCase());
    if (exists) {
      this.submitError = `409 — a category named "${name}" already exists.`;
      return;
    }
    this.submitting = true;
    this.categories.update((list) => [
      ...list,
      { id: 'new-' + list.length, name, sourceCount: 0, articleCount: 0 },
    ]);
    this.submitting = false;
    this.newName = '';
    this.showToast('Category created.');
    this.closeModal();
  }

  deleteCategory(cat: Category): void {
    this.rowError.set(null);
    // The real API returns 422 when active sources are still assigned to the category.
    if (cat.sourceCount > 0) {
      this.rowError.set({
        id: cat.id,
        message: `422 — ${cat.sourceCount} active source(s) still assigned. Reassign or delete them first.`,
      });
      return;
    }
    this.categories.update((list) => list.filter((c) => c.id !== cat.id));
    this.showToast('Category deleted.');
  }

  private showToast(msg: string): void {
    this.toast.set(msg);
    setTimeout(() => this.toast.set(''), 2600);
  }
}
